// Determine AM or PM session
const now = new Date();
const hour = now.getUTCHours();
const session = hour < 12 ? 'am' : 'pm';
const dateStr = now.toISOString().split('T')[0];

// Idempotency key prevents duplicate runs for the same session
const idempotencyKey = `linkedin-monitor:${dateStr}:${session}`;

// RSS feeds from config — listed here for the prompt so the agent
// can cross-reference with config.json at runtime
const rssFeeds = [
  { name: 'IASME', url: 'https://iasme.co.uk/feed/', topics: ['cyber essentials', 'CE Plus', 'IASME Governance'] },
  { name: 'NCSC', url: 'https://www.ncsc.gov.uk/api/1/services/v1/report-rss-feed.xml', topics: ['cyber threats', 'guidance', 'supply chain', 'SME security'] },
  { name: 'ICO', url: 'https://ico.org.uk/about-the-ico/media-centre/news-and-blogs/rss/', topics: ['data protection', 'GDPR', 'enforcement', 'SME guidance'] },
  { name: 'Def Stan', url: 'https://www.gov.uk/government/organisations/defence-equipment-and-support.atom', topics: ['defence standards', 'Def Stan 05-138', 'procurement'] },
  { name: 'ADS Group', url: 'https://www.adsgroup.org.uk/feed/', topics: ['aerospace', 'defence', 'security industry'] }
];

const prompt = `Monitor authority accounts for new content and draft LinkedIn comments.

**Action**: linkedin-monitor
**Date**: ${dateStr}
**Session**: ${session.toUpperCase()} (${hour === 8 ? '08:00' : '14:00'} UTC)

**Instructions**:
1. Read config.json at salesMarketing.linkedin for commentStyle rules (tone, maxLength, avoidPhrases, brandVoice)
2. Fetch each RSS/Atom feed below using WebFetch and check for items published in the last 24 hours:

${rssFeeds.map(f => `   - **${f.name}**: ${f.url}\n     Topics to prioritise: ${f.topics.join(', ')}`).join('\n')}

3. For each new item found:
   a. Summarise the content in 2-3 sentences
   b. Assess urgency: High (< 2 hours old), Medium (2-6 hours), Low (> 6 hours)
   c. Draft a comment under 300 characters that adds genuine value and ends with a question
   d. NEVER use: "Great post!", "Interesting!", "Thanks for sharing!", "Couldn't agree more!"
   e. The comment should reflect OrchestraCode's practitioner experience — not vendor marketing

4. Store all drafts in a single Confluence page:
   - Space: MKTG
   - Location: Social Media/LinkedIn Queue/Comment Drafts
   - Title: "LI-MONITOR - ${dateStr} - ${session.toUpperCase()}"
   - Labels: content-draft, linkedin-monitor

5. If zero new items were found, create the page anyway noting "No new items found in last 24 hours" and end your output with the monitor prefix below.

6. End your output with this EXACT format so the workflow can extract counts:
[AUTO-LINKEDIN-MONITOR] Monitoring complete.
Items found: N
Comment drafts: N
Confluence: [page URL]
Accounts checked: IASME, NCSC, ICO, Def Stan, ADS Group`;

return [{
  json: {
    dateStr,
    session,
    hour,
    idempotencyKey,
    prompt
  }
}];

// Parse the job response to extract monitoring results for Google Chat notification
// The runner returns a jobId immediately; result is available async via callback.
// This node constructs a pending notification -- the callback workflow posts
// the final summary once the agent completes.
const jobId = $input.item.json.jobId || 'unknown';
const session = $('Prepare Monitoring Request').item.json.session;
const dateStr = $('Prepare Monitoring Request').item.json.dateStr;

return [{
  json: {
    jobId,
    session,
    dateStr,
    messageText: `*LinkedIn Monitoring Started* (${session.toUpperCase()})

Date: ${dateStr}
Session: ${session === 'am' ? 'Morning (08:00)' : 'Afternoon (14:00)'}
Job ID: ${jobId}

Checking IASME, NCSC, ICO, Def Stan, ADS Group RSS feeds. Comment drafts will appear in Confluence when complete.

_MKTG > Social Media > LinkedIn Queue > Comment Drafts_`
  }
}];
